class StockSpanner {
public:
    StockSpanner() {
        stack_.push({INT_MAX, 0});
    }

    int next(int price) {
        int span = 1;
        while (!stack_.empty() && stack_.top().first <= price) {
            stack_.pop();
            span += stack_.top().second;
        }
        stack_.push({price, span});
        return span;
    }
private:
    stack<pair<int, int>> stack_;
};
```
